   159	func (s *Store) RunWithOptions(ctx context.Context, definitionID string, opts RunOptions) (RunRecord, error) {
   160		def, doc, err := s.Validate(definitionID)
   161		if err != nil {
   162			return RunRecord{}, err
   163		}
   164		if def.Executor.Kind == ExecutorKindAgent {
   165			if s.AgentRunner == nil {
   166				return RunRecord{}, fmt.Errorf("agent runner not configured for exec definition %q", def.ID)
   167			}
   168	
   169			var promptFile, promptText string
   170			if len(def.Executor.Command) > 0 {
   171				promptFile = def.Executor.Command[0]
   172			} else {
   173				promptText = def.Executor.Env["DDX_AGENT_PROMPT"]
   174			}
   175	
   176			workDir := def.Executor.Cwd
   177			if workDir == "" {
   178				workDir = s.WorkingDir
   179			} else if !filepath.IsAbs(workDir) {
   180				workDir = filepath.Join(s.WorkingDir, workDir)
   181			}
   182	
   183			overrides := config.CLIOverrides{
   184				Harness: def.Executor.Env["DDX_AGENT_HARNESS"],
   185				Model:   def.Executor.Env["DDX_AGENT_MODEL"],
   186				Effort:  def.Executor.Env["DDX_AGENT_EFFORT"],
   187			}
   188			if def.Executor.TimeoutMS > 0 {
   189				timeout := time.Duration(def.Executor.TimeoutMS) * time.Millisecond
   190				overrides.Timeout = &timeout
   191			}
   192			rcfg, _ := config.LoadAndResolve(s.WorkingDir, overrides)
   193	
   194			sessionID := genAgentSessionID()
   195			runtime := agent.AgentRunRuntime{
   196				Prompt:     promptText,
   197				PromptFile: promptFile,
   198				Correlation: map[string]string{
   199					"definition_id":     def.ID,
   200					"artifact_ids":      strings.Join(def.ArtifactIDs, ","),
   201					"produces_artifact": opts.ProducesArtifact,
   202					"session_id":        sessionID,
   203				},
   204				WorkDir: workDir,
   205			}
   206	
   207			start := time.Now().UTC()
   208			agentResult, agentErr := s.AgentRunner.Run(ctx, rcfg, runtime)
   209			finished := time.Now().UTC()
   210	
   211			status := StatusSuccess
   212			exitCode := 0
   213			var stdout, stderr string
   214			if agentErr != nil {
   215				status = StatusErrored
   216				exitCode = 1
   217				stderr = agentErr.Error()
   218			} else {
   219				exitCode = agentResult.ExitCode
   220				stdout = strings.TrimSpace(agentResult.Output)
   221				stderr = strings.TrimSpace(agentResult.Stderr)
   222				if exitCode != 0 {
   223					if exitCode == -1 && strings.Contains(agentResult.Error, "timeout") {
   224						status = StatusTimedOut
   225					} else {
   226						status = StatusFailed
   227					}
   228				}
   229			}
   230	
   231			runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
   232			record := RunRecord{
   233				RunManifest: RunManifest{
   234					RunID:            runID,
   235					DefinitionID:     def.ID,
   236					ArtifactIDs:      def.ArtifactIDs,
   237					ProducesArtifact: opts.ProducesArtifact,
   238					StartedAt:        start,
   239					FinishedAt:       finished,
   240					Status:           status,

---
   240					Status:           status,
   241					ExitCode:         exitCode,
   242					MergeBlocking:    def.Required && status != StatusSuccess,
   243					AgentSessionID:   sessionID,
   244					Attachments:      runAttachmentRefs(s.WorkingDir, runID),
   245					Provenance:       provenance(),
   246				},
   247				Result: RunResult{
   248					Stdout: stdout,
   249					Stderr: stderr,
   250				},
   251			}
   252			if saveErr := s.saveRunRecord(record); saveErr != nil {
   253				return RunRecord{}, saveErr
   254			}
   255			return record, nil
   256		}
   257	
   258		cwd := s.WorkingDir
   259		if def.Executor.Cwd != "" {
   260			if filepath.IsAbs(def.Executor.Cwd) {
   261				cwd = def.Executor.Cwd
   262			} else {
   263				cwd = filepath.Join(s.WorkingDir, def.Executor.Cwd)
   264			}
   265		}
   266	
   267		cmd := osexec.CommandContext(ctx, def.Executor.Command[0], def.Executor.Command[1:]...)
   268		cmd.Dir = cwd
   269		if len(def.Executor.Env) > 0 {
   270			cmd.Env = append(os.Environ(), flattenEnv(def.Executor.Env)...)
   271		}
   272	
   273		start := time.Now().UTC()
   274		stdout, stderr, runErr := captureCommand(cmd)
   275		finished := time.Now().UTC()
   276		duration := finished.Sub(start)
   277	
   278		result := RunResult{
   279			Stdout: strings.TrimSpace(stdout),
   280			Stderr: strings.TrimSpace(stderr),
   281		}
   282		value, unit := normalizeMeasurement(stdout)
   283		if unit == "" && def.Result.Metric != nil {
   284			unit = def.Result.Metric.Unit
   285		}
   286		if unit != "" || value != 0 {
   287			result.Parsed = true
   288			result.Value = value
   289			result.Unit = unit
   290			result.Metric = &MetricObservation{
   291				ArtifactID:   doc.ID,
   292				DefinitionID: def.ID,
   293				ObservedAt:   start,
   294				Value:        value,
   295				Unit:         unit,
   296				Samples:      []float64{value},
   297			}
   298		}
   299	
   300		status := StatusSuccess
   301		exitCode := 0
   302		if runErr != nil {
   303			switch {
   304			case errors.Is(runErr, context.DeadlineExceeded):
   305				status = StatusTimedOut
   306			default:
   307				status = StatusFailed
   308			}
   309			var exitErr *osexec.ExitError
   310			if errors.As(runErr, &exitErr) {
   311				exitCode = exitErr.ExitCode()
   312			} else {
   313				exitCode = 1
   314			}
   315		}
   316		if result.Metric != nil {
   317			result.Metric.Status = metricStatusForRun(status)
   318			if status == StatusSuccess {
   319				result.Metric.Comparison = ComparisonResult{
   320					Baseline:  value,
   321					Delta:     0,
   322					Direction: def.Evaluation.Comparison,
   323				}
   324			}
   325		}
   326	
   327		runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
   328		record := RunRecord{
   329			RunManifest: RunManifest{
   330				RunID:            runID,
   331				DefinitionID:     def.ID,
   332				ArtifactIDs:      def.ArtifactIDs,
   333				ProducesArtifact: opts.ProducesArtifact,
   334				StartedAt:        start,
   335				FinishedAt:       finished,
   336				Status:           status,
   337				ExitCode:         exitCode,
   338				MergeBlocking:    def.Required && status != StatusSuccess,
   339				Attachments:      runAttachmentRefs(s.WorkingDir, runID),
   340				Provenance:       provenance(),
   341			},
   342			Result: result,
   343		}
   344		if writeErr := s.saveRunRecord(record); writeErr != nil {
   345			return RunRecord{}, writeErr
   346		}
   347		_ = duration
   348		return record, nil
   349	}
