   395	func (s *Store) readRunBundle(dir string) (RunRecord, error) {
   396		manifestRaw, err := os.ReadFile(filepath.Join(dir, "manifest.json"))
   397		if err != nil {
   398			return RunRecord{}, err
   399		}
   400		resultRaw, err := os.ReadFile(filepath.Join(dir, "result.json"))
   401		if err != nil {
   402			return RunRecord{}, err
   403		}
   404		var manifest RunManifest
   405		if err := json.Unmarshal(manifestRaw, &manifest); err != nil {
   406			return RunRecord{}, err
   407		}
   408		var result RunResult
   409		if err := json.Unmarshal(resultRaw, &result); err != nil {
   410			return RunRecord{}, err
   411		}
   412		return RunRecord{RunManifest: manifest, Result: result}, nil
   413	}
