322	func (s *Store) runRecordFromBead(b bead.Bead) (RunRecord, error) {
323		var manifest RunManifest
324		if raw, ok := b.Extra["manifest"]; ok {
325			if err := decodeAny(raw, &manifest); err != nil {
326				return RunRecord{}, err
327			}
328		}
329		if manifest.RunID == "" {
330			manifest.RunID = b.ID
331		}
